import{_ as o,o as r,c as t,a3 as a}from"./chunks/framework.CjquFG0V.js";const u=JSON.parse(`{"title":"22. Breaks","description":"","frontmatter":{"title":"22. Breaks","eba":"Children's Services Award 2010","topics":["leave","hours","overtime","shift-work","breaks","preliminary"]},"headers":[],"relativePath":"ebas/childrens-services/hours-of-work/22-breaks.md","filePath":"ebas/childrens-services/hours-of-work/22-breaks.md"}`),s={name:"ebas/childrens-services/hours-of-work/22-breaks.md"};function i(n,e,l,m,p,h){return r(),t("div",null,[...e[0]||(e[0]=[a('<h1 id="_22-breaks" tabindex="-1">22. Breaks <a class="header-anchor" href="#_22-breaks" aria-label="Permalink to &quot;22. Breaks&quot;">​</a></h1><ol><li><p>Meal breaks</p><p>a. An employee will not be required to work in excess of five hours without an unpaid meal break of not less than 30 minutes and not more than one hour. Provided that employees who are engaged for not more than six hours continuously per shift may elect to forego a meal break.</p><p>b. A meal break must be uninterrupted. Where there is an interruption to the meal break and this is occasioned by the employer, overtime will be paid until an uninterrupted break is taken. The minimum overtime payment will be as for 15 minutes with any time in excess of 15 minutes being paid in minimum blocks of 15 minutes.</p></li></ol><p>[22.1(c) substituted by <a href="http://www.fwc.gov.au/documents/awardsandorders/html/PR530861.htm" target="_blank" rel="noreferrer">PR530861</a> ppc 02Nov12]</p><p>c. Notwithstanding clause 22.1(a), where an employee is required to remain on the employer&#39;s premises, the employee will be entitled to a paid meal break of not less than 20 minutes or more than 30 minutes. This paid meal break is to be counted as time worked. By agreement with the employer an employee may leave the premises during the meal break, however, such time away from the premises will not be counted as time worked and nor will any payment be made for such time.</p><ol><li><p>Rest pauses</p><p>a. An employee working four hours or more on any engagement will be entitled to a paid rest period of 10 minutes.</p><p>b. Provided that an employee working for seven hours or more will be entitled to two such paid rest periods of 10 minutes each unless the employee agrees to forego one of these rest periods.</p><p>c. All rest periods must be uninterrupted.</p></li><li><p>Breaks between work periods</p><p>a. All employees will be entitled to a 10 hour rest period between the completion of work on one day and the commencement of work on the next. Work includes any reasonable additional hours or overtime.</p><p>b. Where an employee recommences work without having had 10 hours off work the employee will be paid at overtime rates until such time as they are released from duty for a period of 10 consecutive hours without loss of pay for ordinary time hours occurring during the period of such absence.</p><p>c. By agreement between an employer and an employee the period of 10 hours may be reduced to not less than eight hours.</p></li></ol><p>Plain language terms: meal break, rest break, tea break.</p>',6)])])}const c=o(s,[["render",i]]);export{u as __pageData,c as default};
